import React, {useState} from 'react';

const Hobbies = () => {
    const [isShown, SetShown] = useState({first:false,second:false});

    return(
        <div>
            <h2 className="ui header">Favorite Activities</h2>
            <div className="ui center red segment"
                 onMouseEnter={() => SetShown(isShown.first = true)}
                 onMouseLeave={() => SetShown(isShown.first = false)}
            >
                <h3><i className="heartbeat icon"></i>Gym</h3>
                {isShown.first && (
                    <div className="ui center"><p>Avid Gym goer. Les Mills member since 2 0 1 8! :)</p></div>
                )}
            </div>
            <div className="ui center purple segment"
                 onMouseEnter={() => SetSecondShown(true)}
                 onMouseLeave={() => SetSecondShown(false)}
            >
                <h3><i className="music icon"></i>Piano</h3>
                {secondShown && (
                    <div className="ui center"><p>Avid Gym goer. Les Mills member since 2 0 1 8! :)</p></div>
                )}
            </div>
            <div className="ui center blue segment">
                <h3><img src={require('../resources/swimming.png')} style={{width:"1.5em",paddingRight:"0.3em",height:"1em"}}/>Swimming</h3>
            </div>
        </div>
    )
};

export default Hobbies;
